    endif
    ADDR = ENCODE_ADDR(stack_base, stack_index).

function DATA_VALID(data):
    if data == INVALID_NODE
         return false
    elsif last_node_ptr != INVALID_NODE && data == last_node_ptr
         // Match last_node_ptr
         return false
    else
         return true
    endif
endfunction.

